```javascript
function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    let maxW = edges[edges.length - 1][2];
    let low = 0, high = maxW;

    function isPossible(X) {
        let parent = Array(n).fill(0).map((_, i) => i);
        let rank = Array(n).fill(0);
        let count = n;

        function find(x) {
            if (parent[x] !== x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        function union(x, y) {
            let xroot = find(x);
            let yroot = find(y);
            if (xroot === yroot) return;
            if (rank[xroot] < rank[yroot]) {
                parent[xroot] = yroot;
            } else {
                parent[yroot] = xroot;
                if (rank[xroot] === rank[yroot]) {
                    rank[xroot]++;
                }
            }
            count--;
        }

        for (let edge of edges) {
            if (edge[2] <= X) {
                union(edge[0], edge[1]);
            }
        }

        return count <= k;
    }

    while (low < high) {
        let mid = Math.floor((low + high) / 2);
        if (isPossible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }

    return low;
}
